define("quiz_paperentry/mapping_widget",[],(function(){"use strict";function setup(widgetid,fromlabel,tolabel,inject){var widget=document.getElementById(widgetid);if(!widget)return null;var rows=widget.querySelector(".pe-map-rows"),addBtn=widget.querySelector(".pe-map-add");function addRow(from,to){var row=document.createElement("div");row.className="pe-map-row d-flex align-items-center mb-1";row.style.gap="6px";var fi=document.createElement("input");fi.type="text";fi.name=inject?"":"remap_from[]";fi.placeholder=fromlabel;fi.value=from||"";fi.className="form-control form-control-sm";fi.style.width="110px";fi.dataset.role="from";var arrow=document.createElement("span");arrow.textContent="→";var ti=document.createElement("input");ti.type="text";ti.name=inject?"":"remap_to[]";ti.placeholder=tolabel;ti.value=to||"";ti.className="form-control form-control-sm";ti.style.width="110px";ti.dataset.role="to";var del=document.createElement("button");del.type="button";del.textContent="×";del.className="btn btn-sm btn-outline-danger";del.addEventListener("click",(function(){row.remove()}));row.appendChild(fi);row.appendChild(arrow);row.appendChild(ti);row.appendChild(del);rows.appendChild(row)}addBtn.addEventListener("click",(function(){addRow("","")}));if(inject){var cardBody=widget.closest(".card-body"),form=cardBody?cardBody.querySelector("form"):null;if(form)form.addEventListener("submit",(function(){rows.querySelectorAll(".pe-map-row").forEach((function(r){var from=r.querySelector("[data-role=from]").value.trim(),to=r.querySelector("[data-role=to]").value.trim();if(from){var hf=document.createElement("input");hf.type="hidden";hf.name="remap_from[]";hf.value=from;form.appendChild(hf);var ht=document.createElement("input");ht.type="hidden";ht.name="remap_to[]";ht.value=to;form.appendChild(ht)}}))}))}return{addRow:addRow}}return{init:function(widgetid,fromlabel,tolabel,inject){setup(widgetid,fromlabel,tolabel,inject)},initWithSaved:function(widgetid,fromlabel,tolabel,inject,savedpairs){var instance=setup(widgetid,fromlabel,tolabel,inject);if(instance&&savedpairs&&typeof savedpairs==="object"){Object.entries(savedpairs).forEach((function(e){instance.addRow(e[0],e[1])}))}}}}));
